<template>
	<div class="co-table"
		:class="[ {
			'co-table-border': border,
			'co-table-hidden': hidden
		}, tableSize ? 'co-table-' + tableSize : '' ]"
	>
		<div class="co-table-wrapper"	v-if="showTable" ref="tableWrappper">
			<table>
				<template v-if="showTable">
					<thead class="co-table-header">
						<tr>
							<template v-for="tableCols in tableHeader">
								<th @click="orderBy(tableCols)">
									{{tableCols}}
									<i :class="setSortBy[tableCols] > 0 ? 'asc fas fa-caret-down' : 'desc fas fa-caret-up'"></i>
								</th>
							</template>
						</tr>
					</thead>
					<tbody>
						<template v-for="(itemData, itemNum) in tableBody">
							<tr row-index="itemNum">
								<template v-for="tableCols in tableHeader" >
									<td v-if="itemData[tableCols]" key="itemNum">{{ itemData[tableCols] }}</td>
									<td v-else >{{'Null'}}</td>
								</template>
							</tr>
						</template>
					</tbody>
					<tfoot>
						<slot name="tfoot" :rows="tableFoot"></slot>
					</tfoot>
				</template>
			</table>
	</div>

  <div class="co-pagination-wrapper">
    	<div class="co-pagination-styles">
    		<div class="co-pagination-styles-index">
  				<span href="#">总共&nbsp;<strong class="order-total">{{ totalMount }}</strong>&nbsp;数量</span>
  			</div>

        <div class="co-pagination-styles-group">
  				<button @click="goPage(0)" :class="{disabled: isFirstPage}">Start</button>

  				<button @click="goPrevPage(tablePagination)" :class="{disabled: isFirstPage}">
  					<i class="fas fa-chevron-left"></i>
  				</button>
  				<template v-for="i in totalPage">
  					<button @click="goPage(i-1)" :class="{active: isCurrentPage(i-1)}">{{i}}</button>
  				</template>
  				<button @click="goNextPage(tablePagination)" :class="{disabled: isLastPage}">
  					<i class="fas fa-chevron-right"></i>
  				</button>

  				<button @click="goPage(totalPage-1)" :class="{disabled: isLastPage}">End</button>
    	  </div>

      </div>
  </div>
</div>
</template>
<script>

export default {
	name: 'coTable',

	data() {
		return {
			showTable: true,

      // table data part split start
			tableHeader: this.columns,
			tableBody: this.rows.slice(0, this.perPage),
			tableFoot: [],
      // table data part split end

      // sort start
      sortKey: null,
      setSortBy: {},
      multiSort: null,
      triggerSort: false,
			// sort end

			search: '',

      tablePagination: 0,
      initTablePagination: 5,
      // 第一个分页
			isFirstPage: 0,
      //
			isLastPage: 0,

      // 所有数据的数量之和
			totalMount: this.rows.length,

			savePageArr: [],
      // 所以分页数量
      totalPage: 1,
		}
	},

	props: {

		tableSize: Number,

		hidden: {
			type: Boolean,
			default: false
		},

		border: {
			type: Boolean,
			default: false
		},

		value: {
			type: String,
			default: ''
		},

		columns: {
			type: Array,
			default: []
		},

		visible: {
			type: Boolean,
			default: true
		},

		rows: {
			type: Array,
			default: []
		},

		perPage: {
			type: Number,
			default: 10
		}
	},

	mounted() {
		if(!this.visible) this.showTable = this.visible
	},

  created() {
    this.columns.forEach((items) => {
      this.setSortBy[items] = 1
    })

    this.defaultTotalPage()
  },

	methods: {
    // 点击倒序排序
		orderBy(titleName) {
			this.sortKey = titleName
			this.setSortBy[titleName] *= -1

			if (this.triggerSort) this.triggerSort = false
			else this.triggerSort = true
		},

    // 搜索排序
		searchBy(val) {
			let resource = this.rows

			if(val == ''){
				this.tableBody = resource.slice(0, this.perPage)
			}
			else {
				this.tableBody = resource.filter((items) => {
					return Object.keys(items).some((key) => {
						return String(items[key]).indexOf(val) >= 0
					})
				}).slice(0, this.perPage)
			}
		},

    // 如果重复当前页面
    // 无状态
    isCurrentPage(val) {
      if(val == 0 && this.tablePagination == val) return true;
      return val == this.tablePagination
    },

    // num从0开始的计算的
    // 去结束页
		goPage(num) {
			this.tableBody = this.showCurrentPaginationData(num) // 索引当前分页数据
			this.tablePagination = num //  索引当前分页index
		},

    // 去上一页
		goPrevPage(num) {
			if(isNaN(num)) num = 0
			else num -= 1

      // 如果点击到第一条数据 禁止继续往上
      // 后续添加新功能
      // tips 提示信息
			if(num < 1) num = 0

			this.tablePagination = num
			this.tableBody = this.showCurrentPaginationData(num) // 索引当前分页数据
		},

    // 去下一页
		goNextPage(num)　{
			if(isNaN(num)) num = 1
			else num += 1

      // 如果点击到最后一条数据 禁止继续往下
      // 后续添加新功能
      // tips 提示信息
      if(num >= this.totalPage) return false;

			this.tablePagination = num
			this.tableBody = this.showCurrentPaginationData(num) // 索引当前分页数据
		},

    // 分页数量 totalPage
    // 初始化第一次计算所有分页
    defaultTotalPage() {
      let rowsLength = this.rows.length
      let arr = []

      // 少于10条数据
      // 每一页的数量 默认 10 条数据
      if (rowsLength <= 10) {
        arr.push(1)
      }
      else {
        arr.push(Math.ceil(rowsLength / this.perPage))
      }

      this.totalPage = arr.shift()
    },

    showCurrentPaginationData(num) {
      let showResource
      // 当前页数量

      if(num <= 0) {
        showResource = this.rows.slice(0, this.perPage)
      }
      else {
        // 如果当前页的数量 少于 默认每页的数量
        // 就会取当前页不足默认每页的数量
        // 假如perpage =10 也就是取得不足 10 的剩余数量
        let currentLastPageAmount = this.totalMount - (num * this.perPage)
        if(currentLastPageAmount < this.perPage) {
          showResource = this.rows.slice(-currentLastPageAmount)
        }
        else {
          showResource = this.rows.slice(num * this.perPage, (num + 1) * this.perPage)
        }
      }

      return showResource
    },
	},

	watch: {
		triggerSort(oldval,newval) {
			var resource = this.rows
			var id = this.sortKey
			var setSortBoolean = this.setSortBy[id]

      // 设置排序 倒序
			let results = resource.sort(function (e, c) {
				e = e[id]
				c = c[id]

        // 非数字情况 排序
        if(isNaN(e) && isNaN(c)) {
          // 没有找到 为null 或undefined 不进行排序
          if(typeof e == 'undefined' || typeof c == 'undefined') {
            c = e = 0
          }
          // 如果是字符串 比较 length 排序
          e = e.toString().length
          c = c.toString().length
          return setSortBoolean < 0 ? c - e : e - c
        }

        // 数字id排序
				return setSortBoolean < 0 ? c - e : e - c
			})

      // this.tablePagination 根据页面进行排序
			this.tableBody = results.slice(this.tablePagination * this.perPage, (this.tablePagination + 1) * this.perPage)
		},

		value(oldval, newval) {
			let previousValue = oldval.toString().toLowerCase()
			let nextValue = newval.toString().toLowerCase()

			if(previousValue == nextValue) return null
			else this.searchBy(previousValue)
		}
	},
}
</script>
<style lang="less">
.co-table{
	position: relative;
	overflow: hidden;
	box-sizing: border-box;
	flex: 1;
	width: 100%;
	max-width: 100%;
	background-color: #fff;
	font-size: 14px;
	color: #606266;
}
.co-table td, .co-table th {
    padding: 12px 0;
    min-width: 0;
    box-sizing: border-box;
    text-overflow: ellipsis;
    vertical-align: middle;
    position: relative;
}
.co-table .cell {
    box-sizing: border-box;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: normal;
    word-break: break-all;
    line-height: 23px;
    padding-left: 10px;
    padding-right: 10px;
}
.co-table-wrapper table{
    display: table;
    width: 100%;
    height: 100%;
    margin: 0;
    padding: 0;
    text-indent: 0;
    text-align: center;
    font-size: inherit;
    font-weight: normal;
    border: 0px solid #ddd;
    border-spacing: 0;
    background-color: #fff;
    overflow: hidden;
}
.co-table-wrapper table >thead{
    display: table-header-group;
    margin: 0;
    padding: 0;
}
.co-table-wrapper table >thead > tr{
    display: table-row;
    background-color: #F9FAFB
}
.co-table-wrapper table >thead > tr > th{
    display: table-cell;
    text-align: left;
    margin: 0;
    padding: 16px 10px;
    height: 0;
    font-weight: bold;
    vertical-align: middle!important;
    border: 0px solid #eee;
    border-top: 2px solid #D3E7F5;
    border-bottom-width: 1px;
    border-left-width: 1px;
    cursor: pointer;
}
.co-table-wrapper table >thead > tr > th > i {
	font-size: 20px;
	margin-left: 6px;
}
.co-table-wrapper table >thead > tr > th:first-child{
    border-left-width:1px;
}
.co-table-wrapper table >thead > tr > th:last-child{
    border-right-width:1px;
}
.co-table-wrapper table >tbody{
    display: table-header-group;
    margin: 0;
    padding: 0;
}
.co-table-wrapper table >tbody{
}
.co-table-wrapper table >tbody >tr{
}
.co-table-wrapper table >tbody >tr >td{
    display: table-cell;
    text-align: left;
    margin: 0;
    padding: 16px 10px;
    border-spacing: 0;
    border: 0px #EEE solid;
    border-bottom-width: 1px;
    border-left-width: 1px;
}
.co-table-wrapper table >tbody >tr >td:first-child{
    border-left-width:1px;
}
.co-table-wrapper table >tbody >tr >td:last-child{
    border-right-width:1px;
}
.co-table-wrapper table >tbody >tr:nth-of-type(odd){
    background-color: #FEFEFE
}
.co-table-wrapper table >tbody >tr:nth-of-type(even){
    background-color: #F9FAFB
}
.co-table-wrapper table >tbody >tr:hover:nth-of-type(odd){
    background-color: #FDFDFD;
    color: #222;
}
.co-table-wrapper table >tbody >tr:hover:nth-of-type(even){
    background-color: #F8F9FA;
    color: #222;
}

.co-pagination-wrapper{
	float: left;
	width: 100%;
}
.co-pagination-wrapper .co-pagination-styles{
    display: inline-block;
  	float: left;
    margin-top: 15px;
    text-align: right;
	width: 100%;
}
.co-pagination-wrapper .co-pagination-styles .co-pagination-styles-group{
  display:inline-block;
}
.co-pagination-wrapper .co-pagination-styles .co-pagination-styles-index{
	float: left;
}
.co-pagination-wrapper .co-pagination-styles .co-pagination-styles-group >span{
    text-align: center;
    font-size: 14px;
    color: #888
}
.co-pagination-wrapper .co-pagination-styles .co-pagination-styles-group >button{
  display:inline-block;
  position: relative;
  float: left;
  padding: 0;
  margin: 0;
  width: 42px;
  height: 40px;
  line-height: 40px;
  border-radius: 0px;
  font-size: 16px;
  text-align: center;
  text-decoration: none;
  vertical-align: middle;
  border: 1px solid #DEDEDE;
  border-left: none;
  cursor: pointer;
  background-color: #FFF;
  color: #333;
  outline: none
}
.co-pagination-wrapper .co-pagination-styles .co-pagination-styles-group button:first-child{
	border-left: 1px solid #DEDEDE;
	border-radius: 3px 0 0 3px;
}
.co-pagination-wrapper .co-pagination-styles .co-pagination-styles-group >button:last-child{
	border-radius: 0 3px 3px 0;
}
.co-pagination-wrapper .co-pagination-styles .co-pagination-styles-group >button:hover{
    background-color: #FEFEFE;
}
/*.co-pagination-wrapper .co-pagination-styles .co-pagination-styles-group button:first-child,
.co-pagination-wrapper .co-pagination-styles .co-pagination-styles-group >button:last-child{
}*/
.co-pagination-wrapper .co-pagination-styles .co-pagination-styles-group button:first-child:hover{
    background-color: #EEE;
    color: #333;
}
.co-pagination-wrapper .co-pagination-styles .co-pagination-styles-group >button:last-child:hover{
    background-color: #EEE;
    color: #333;
}
.co-pagination-wrapper .co-pagination-styles .co-pagination-styles-group >button.active{
    background-color: #F2F2F2;
    color: #111;
}
.co-pagination-wrapper .co-pagination-styles .co-pagination-styles-group >button.active:hover{
  border-color: #DEDEDE;
}
.co-pagination-wrapper .co-pagination-styles .co-pagination-styles-index{
    height: 32px;
    clear: both;
}
.co-pagination-wrapper .co-pagination-styles .co-pagination-styles-index span{
    display: inline-block;
    margin: 0 0 0 6px;
    line-height: 40px;
    white-space: nowrap;
    vertical-align: middle;
    border-spacing: 0;
    text-align: center;
    font-size: 16px;
    color: #888;
}
.co-pagination-wrapper .co-pagination-styles .co-pagination-styles-index span strong{
    font-weight: normal;
    color: #333;
}

.body-empty{
  width: 100%;
  height: 300px;
  line-height: 300px;
  text-align: center;
}
</style>




